#include<bits/stdc++.h>
using namespace std;

long long ans,l,r;
long long s[100005],t[100005];

int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++) cin>>s[i]>>t[i];
    sort(s+1,s+1+n);
     l = s[1];
     r =t[1];
     for(int i=2;i<=n;i++) {
         if(s[i]<=r){
             r = max(r, t[i]);
         }else{
             ans+=r-l+1;
             l = s[i];
            r = t[i];
         }
     }
     ans+=r-l+1;
    cout<<ans;
    return 0;
}
